{"name": "rss_polling", "kind": "polling", "polling_interval": "60s", "description": "轮询 RSS 订阅源，使用 cursor 机制避免重复触发。返回自上次轮询以来的新条目。", "code": "import feedparser
from datetime import datetime, timezone
from typing import Optional, Dict, Any, List


def rss_polling(
    feed_url: str,
    cursor: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    """
    轮询 RSS feed，返回新条目。

    参数:
        feed_url: RSS 订阅地址
        cursor: 上次轮询的游标状态，包含 last_entry_id 和 last_checked

    返回:
        {
            "new_entries": [...],   # 新增条目列表
            "cursor": {...},        # 更新后的游标
            "count": int,           # 新增数量
        }
    """
    if cursor is None:
        cursor = {
            "last_entry_id": None,
            "last_checked": None,
        }

    feed = feedparser.parse(feed_url)

    # 处理解析错误
    if feed.bozo and not feed.entries:
        return {
            "error": f"解析 RSS 失败: {feed.bozo_exception}",
            "new_entries": [],
            "cursor": {**cursor, "last_checked": datetime.now(timezone.utc).isoformat()},
            "count": 0,
        }

    entries: List[Dict[str, Any]] = []
    for entry in feed.entries:
        entries.append({
            "id": entry.get("id") or entry.get("link", ""),
            "title": entry.get("title", ""),
            "link": entry.get("link", ""),
            "published": entry.get("published", ""),
            "published_parsed": entry.get("published_parsed"),
            "summary": entry.get("summary", ""),
            "author": entry.get("author", ""),
            "tags": [t.get("term", "") for t in entry.get("tags", [])],
        })

    last_entry_id = cursor.get("last_entry_id")
    new_entries: List[Dict[str, Any]] = []

    if last_entry_id is None:
        # 首次运行：只取最新的条目作为基线，暂不触发
        if entries:
            new_cursor = {
                "last_entry_id": entries[0]["id"],
                "last_checked": datetime.now(timezone.utc).isoformat(),
            }
            return {
                "new_entries": [],
                "cursor": new_cursor,
                "count": 0,
                "message": "首次初始化，已记录最新条目位置，下次轮询将返回新增内容",
            }
    else:
        # 非首次：遍历，遇到上次的 last_entry_id 就停止
        found_last = False
        for entry in entries:
            if entry["id"] == last_entry_id:
                found_last = True
                break
            # entries 按时间倒序（最新的在前），
            # 所以遍历到的都是比 last 更新的条目
            new_entries.append(entry)

        # 如果没找到 last_entry_id（比如 feed 彻底刷新了），
        # 则返回全部条目作为新的
        if not found_last and entries:
            new_entries = entries

    # 更新 cursor
    if entries:
        new_cursor = {
            "last_entry_id": entries[0]["id"],
            "last_checked": datetime.now(timezone.utc).isoformat(),
        }
    else:
        new_cursor = {
            **cursor,
            "last_checked": datetime.now(timezone.utc).isoformat(),
        }

    # 新条目按时间正序返回，方便下游处理
    new_entries.reverse()

    return {
        "new_entries": new_entries,
        "cursor": new_cursor,
        "count": len(new_entries),
    }
"}
